noncompliant:
// In C - using inappropriate types
struct BitField {
  int b1 : 3;          // Noncompliant - may have implementation-dependent behavior
  float b2 : 2;        // Noncompliant - float not suitable for bit fields
  double b3 : 1;       // Noncompliant - double not suitable
  char* b4 : 4;        // Noncompliant - pointer type not suitable
};

compliant:
// In C - using appropriate types
struct BitField {
  signed short b1 : 3;     // Compliant
  unsigned short b2 : 2;   // Compliant
  signed char b3 : 1;      // Compliant
  unsigned char b4 : 4;    // Compliant
  signed int b5 : 5;       // Compliant
  unsigned int b6 : 6;     // Compliant
  _Bool b7 : 1;            // Compliant
};

// In C++14 and later - additional safe types
enum class Status : char { ACTIVE, INACTIVE };
struct CppBitField {
  bool flag : 1;           // Compliant
  Status status : 2;       // Compliant (enumerated type)
  signed long long val : 8; // Compliant (C++14+)
};
